     1→/*
     2→ * ldexpf() test harness -- prints (input_hex, exponent, output_hex) triples.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly ldexpf  (test_ldexpf_opt.elf)
     6→ *   2. Linked with toolchain's default ldexpf        (test_ldexpf_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→#ifdef EN_PERF
    16→#define PF_COUNTER
    17→#include "nds_pfcounter.h"
    18→#endif
    19→
    20→static inline uint32_t f2u(float f)
    21→{
    22→    union { float f; uint32_t u; } x;
    23→    x.f = f;
    24→    return x.u;
    25→}
    26→
    27→static inline float u2f(uint32_t u)
    28→{
    29→    union { float f; uint32_t u; } x;
    30→    x.u = u;
    31→    return x.f;
    32→}
    33→
    34→#ifdef EN_PERF
    35→static volatile float g_acc;
    36→
    37→static void emit(float x, int exp)
    38→{
    39→    volatile float vx = x;   /* prevent constant-folding of literal arguments */
    40→    g_acc += ldexpf(vx, exp);
    41→}
    42→
    43→static void emit_u(uint32_t bits, int exp)
    44→{
    45→    emit(u2f(bits), exp);
    46→}
    47→#else
    48→static void emit(float x, int exp)
    49→{
    50→    float r = ldexpf(x, exp);
    51→    printf("%08lx %d %08lx\n",
    52→           (unsigned long)f2u(x), exp, (unsigned long)f2u(r));
    53→}
    54→
    55→static void emit_u(uint32_t bits, int exp)
    56→{
    57→    emit(u2f(bits), exp);
    58→}
    59→#endif
    60→
    61→/* ------------------------------------------------------------------ */
    62→/* Representative 100-point test                                       */
    63→/* ------------------------------------------------------------------ */
    64→
    65→static void test_representative_100(void)
    66→{
    67→    /* --- Section 1: Special IEEE 754 values for x (7) --- */
    68→    emit(0.0f, 0);                    /* +zero, n=0 -> +zero */
    69→    emit(-0.0f, 0);                   /* -zero, n=0 -> -zero */
    70→    emit_u(0x7fc00000u, 5);           /* qNaN -> qNaN */
    71→    emit_u(0x7f800001u, 5);           /* sNaN -> NaN */
    72→    emit_u(0xffc00000u, 5);           /* -qNaN -> -qNaN */
    73→    emit_u(0x7f800000u, 5);           /* +Inf * 2^5 -> +Inf */
    74→    emit_u(0xff800000u, 5);           /* -Inf * 2^5 -> -Inf */
    75→
    76→    /* --- Section 2: Subnormal x values (6) --- */
    77→    emit_u(0x00000001u, 0);           /* min positive subnormal: 2^-149, n=0 */
    78→    emit_u(0x80000001u, 0);           /* min negative subnormal, n=0 */
    79→    emit_u(0x00400000u, 0);           /* mid positive subnormal, n=0 */
    80→    emit_u(0x80400000u, 0);           /* mid negative subnormal, n=0 */
    81→    emit_u(0x007fffffu, 0);           /* max subnormal: just below FLT_MIN, n=0 */
    82→    emit_u(0x807fffffu, 0);           /* max negative subnormal, n=0 */
    83→
    84→    /* --- Section 3: Normal boundary x values (6) --- */
    85→    emit_u(0x00800000u, 0);           /* FLT_MIN = 2^-126, n=0 */
    86→    emit_u(0x80800000u, 0);           /* -FLT_MIN, n=0 */
    87→    emit_u(0x00800001u, 0);           /* one ULP above FLT_MIN, n=0 */
    88→    emit_u(0x7f7fffffu, 0);           /* FLT_MAX, n=0 */
    89→    emit_u(0xff7fffffu, 0);           /* -FLT_MAX, n=0 */
    90→    emit_u(0x7f7ffffeu, 0);           /* one ULP below FLT_MAX, n=0 */
    91→
    92→    /* --- Section 4: Near 1.0 x values (6) --- */
    93→    emit_u(0x3f7fffffu, 0);           /* one ULP below 1.0, n=0 */
    94→    emit(1.0f, 0);                    /* 1.0 * 2^0 = 1.0 */
    95→    emit_u(0x3f800001u, 0);           /* one ULP above 1.0, n=0 */
    96→    emit(-1.0f, 0);                   /* -1.0 * 2^0 = -1.0 */
    97→    emit_u(0xbf7fffffu, 0);           /* one ULP toward zero from -1.0 */
    98→    emit_u(0xbf800001u, 0);           /* one ULP away from zero from -1.0 */
    99→
   100→    /* --- Section 5: Overflow cases (large positive n) (8) --- */
   101→    emit(1.0f, 127);                  /* 1.0 * 2^127: exponent = 127, max normal exp */
   102→    emit(1.0f, 128);                  /* 1.0 * 2^128 -> overflow to +Inf */
   103→    emit(0.5f, 128);                  /* 0.5 * 2^128 = 2^127 = FLT_MAX exponent */
   104→    emit(0.5f, 129);                  /* 0.5 * 2^129 -> overflow */
   105→    emit(-1.0f, 128);                 /* -1.0 * 2^128 -> -Inf */
   106→    emit(1.0f, 200);                  /* very large n -> +Inf */
   107→    emit(-1.0f, 200);                 /* very large n -> -Inf */
   108→    emit_u(0x7f7fffffu, 1);           /* FLT_MAX * 2 -> overflow */
   109→
   110→    /* --- Section 6: Underflow cases (large negative n) (8) --- */
   111→    emit(1.0f, -127);                 /* 1.0 * 2^-127: first subnormal from 1.0 */
   112→    emit(1.0f, -149);                 /* 1.0 * 2^-149 = min positive subnormal */
   113→    emit(1.0f, -150);                 /* 1.0 * 2^-150: underflow to zero */
   114→    emit(-1.0f, -150);                /* underflow to -zero */
   115→    emit(1.0f, -200);                 /* deep underflow -> +zero */
   116→    emit(-1.0f, -200);                /* deep underflow -> -zero */
   117→    emit_u(0x00800000u, -1);          /* FLT_MIN * 2^-1 = max subnormal */
   118→    emit_u(0x00000001u, -1);          /* min subnormal * 2^-1 -> zero (underflow) */
   119→
   120→    /* --- Section 7: Normal-to-subnormal (gradual underflow) (10) --- */
   121→    emit_u(0x00800000u, -1);          /* FLT_MIN * 2^-1: first subnormal */
   122→    emit_u(0x00800000u, -2);          /* FLT_MIN * 2^-2 */
   123→    emit_u(0x00800000u, -10);         /* FLT_MIN * 2^-10 */
   124→    emit_u(0x00800000u, -23);         /* FLT_MIN * 2^-23: approaching min subnormal */
   125→    emit_u(0x01000000u, -24);         /* 2*FLT_MIN * 2^-24 = min subnormal */
   126→    emit_u(0x01000000u, -25);         /* below min subnormal -> zero */
   127→    emit(1.5f, -149);                 /* 1.5 * 2^-149 = 1 ULP into subnormals */
   128→    emit(1.5f, -126);                 /* 1.5 * 2^-126: just above FLT_MIN */
   129→    emit(1.5f, -127);                 /* 1.5 * 2^-127: subnormal */
   130→    emit(1.25f, -127);                /* 1.25 * 2^-127: another subnormal */
   131→
   132→    /* --- Section 8: Subnormal-to-normal (positive n shifts into normal range) (8) --- */
   133→    emit_u(0x00000001u, 149);         /* min subnormal * 2^149 = 1.0 */
   134→    emit_u(0x00000001u, 148);         /* min subnormal * 2^148 = 0.5 */
   135→    emit_u(0x007fffffu, 1);           /* max subnormal * 2: just below FLT_MIN */
   136→    emit_u(0x007fffffu, 2);           /* max subnormal * 4: normal */
   137→    emit_u(0x00400000u, 1);           /* mid subnormal * 2 */
   138→    emit_u(0x00400000u, 2);           /* mid subnormal * 4 */
   139→    emit_u(0x80000001u, 149);         /* min neg subnormal * 2^149 = -1.0 */
   140→    emit_u(0x807fffffu, 2);           /* max neg subnormal * 4: negative normal */
   141→
   142→    /* --- Section 9: Identity n=0 with varied normal x (10) --- */
   143→    emit(0.1f, 0);
   144→    emit(0.5f, 0);
   145→    emit(1.5f, 0);
   146→    emit(2.0f, 0);
   147→    emit(10.0f, 0);
   148→    emit(100.0f, 0);
   149→    emit(-0.5f, 0);
   150→    emit(-1.5f, 0);
   151→    emit(-10.0f, 0);
   152→    emit(-100.0f, 0);
   153→
   154→    /* --- Section 10: Exponent sweep with varied bases (31) --- */
   155→    /* n = -10 to +10 with base 1.0 (20 points, skip n=0 already in Section 9) */
   156→    emit(1.0f, -10);
   157→    emit(1.0f, -9);
   158→    emit(1.0f, -8);
   159→    emit(1.0f, -7);
   160→    emit(1.0f, -6);
   161→    emit(1.0f, -5);
   162→    emit(1.0f, -4);
   163→    emit(1.0f, -3);
   164→    emit(1.0f, -2);
   165→    emit(1.0f, -1);
   166→    emit(1.0f, 1);
   167→    emit(1.0f, 2);
   168→    emit(1.0f, 3);
   169→    emit(1.0f, 4);
   170→    emit(1.0f, 5);
   171→    emit(1.0f, 6);
   172→    emit(1.0f, 7);
   173→    emit(1.0f, 8);
   174→    emit(1.0f, 9);
   175→    emit(1.0f, 10);
   176→    /* Additional bases with varied n (11 points) */
   177→    emit(0.75f, -1);                  /* 0.75 * 0.5 = 0.375 */
   178→    emit(0.75f, 1);                   /* 0.75 * 2 = 1.5 */
   179→    emit(1.5f, -1);                   /* 1.5 * 0.5 = 0.75 */
   180→    emit(1.5f, 1);                    /* 1.5 * 2 = 3.0 */
   181→    emit(-0.75f, 2);                  /* -0.75 * 4 = -3.0 */
   182→    emit(-1.5f, -2);                  /* -1.5 * 0.25 = -0.375 */
   183→    emit(1.0f, 126);                  /* large but not overflow */
   184→    emit(1.0f, -126);                 /* small but still normal */
   185→    emit(0.5f, 127);                  /* 0.5 * 2^127: FLT_MAX / 2 */
   186→    emit(-0.5f, 127);                 /* -0.5 * 2^127 */
   187→    emit(0.5f, -126);                 /* 0.5 * 2^-126: subnormal */
   188→}
   189→
   190→/* ------------------------------------------------------------------ */
   191→/* Dense sweep (accuracy path only)                                   */
   192→/* ------------------------------------------------------------------ */
   193→
   194→#ifndef EN_PERF
   195→/* Sample mantissa [0.5, 1) with base exponent */
   196→static void test_exhaustive_small(void)
   197→{
   198→    uint32_t start = 0x3f000000u; /* 0.5 */
   199→    uint32_t end = 0x3f800000u;   /* 1.0 */
   200→    int exp = 10;
   201→
   202→    for (uint32_t b = start; b <= end; b += 2097152)
   203→        emit_u(b, exp);
   204→}
   205→#endif
   206→
   207→/* ------------------------------------------------------------------ */
   208→
   209→int main(void)
   210→{
   211→#ifdef EN_PERF
   212→    startPFM;
   213→    test_representative_100();
   214→    stopPFM;
   215→    readResult();
   216→    printf("perf g_acc: %08lx\n", (unsigned long)f2u((float)g_acc));
   217→#else
   218→    test_representative_100();
   219→    test_exhaustive_small();
   220→#endif
   221→    return 0;
   222→}
